+
+        assert!(matches!(zone.status(), ZoneStatus::Active));
+
+        zone.pause();
+        assert!(matches!(zone.status(), ZoneStatus::Paused));
+
+        zone.resume();
+        assert!(matches!(zone.status(), ZoneStatus::Active));
+
+        zone.complete();
+        assert!(matches!(zone.status(), ZoneStatus::Complete));
+    }
+}

