+    /// Create a new hardware adapter with specific configuration
+    pub fn with_config(config: HardwareConfig) -> Self {
+        Self {
+            config,
+            sensors: Vec::new(),
+            initialized: false,
+            csi_broadcaster: None,
+            state: Arc::new(RwLock::new(DeviceState {
+                streaming: false,
+                packets_received: 0,
+                error_count: 0,
+                last_error: None,
+                device_state: DeviceSpecificState::Other,
+            })),
+            shutdown_tx: None,
+        }
